explicitReceiver.name:
activeTokens.values
                .map { record: BarrierTokenRecord ->
                    record.copy(
                        aliveMs = (nowUptimeMs - record.postUptimeMs).coerceAtLeast(minimumValue = 0L),
                    )
                }
                .filter { record: BarrierTokenRecord -> record.aliveMs >= thresholdMs }

runCatching {
            stackReader()
                .filterKeys { thread: Thread -> isBinderThread(thread = thread) }
                .entries
                .take(n = maxThreadCount)
                .flatMap { entry: Map.Entry<Thread, Array<StackTraceElement>> ->
                    entry.value
                        .take(n = maxFramesPerThread)
                        .map { frame: StackTraceElement -> frame.toString() }
                }
        }

runCatching {
                val field = Looper::class.java.getDeclaredField("mLogging")
                field.isAccessible = true
                field.get(looper) as? Printer
            }

messages
            .mapNotNull { message -> message.targetClass ?: message.callbackClass }
            .groupingBy { key -> key }

messages
            .mapNotNull { message -> message.targetClass ?: message.callbackClass }
            .groupingBy { key -> key }
            .eachCount()

messages
            .mapNotNull { message -> message.targetClass ?: message.callbackClass }
            .groupingBy { key -> key }
            .eachCount()
            .values

statReader()
                .map { stat: ThreadCpuStat -> stat.toRecord() }
                .sortedByDescending { record: ThreadCpuRecord -> record.totalCpuMs }

runCatching {
            statReader()
                .map { stat: ThreadCpuStat -> stat.toRecord() }
                .sortedByDescending { record: ThreadCpuRecord -> record.totalCpuMs }
                .take(n = maxCount)
        }

eventId.map { char: Char ->
            if (char.isLetterOrDigit() || char == '-' || char == '_' || char == '.') {
                char
            } else {
                '_'
            }
        }

reports.values
            .filter { report: QueuedReport -> report.nextRetryUptimeMs <= nowUptimeMs }
            .sortedBy { report: QueuedReport -> report.nextRetryUptimeMs }

Thread(
                {
                    runCpuContentionLoop(
                        threadName = threadName,
                        contentionDurationMs = contentionDurationMs,
                        running = running,
                        startedLatch = startedLatch,
                    )
                },
                threadName,
            )
